# -*- coding: utf-8 -*-
"""检查 SDK 内部状态"""

import asyncio
from playwright.async_api import async_playwright

BASE_URL = "http://localhost:10280"

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        context = await browser.new_context()
        page = await context.new_page()

        page.on("console", lambda msg: print(f"[Console] {msg.text}"))

        await page.goto(BASE_URL, wait_until="networkidle")
        await page.wait_for_timeout(1000)

        # 点击设备管理并连接
        devices_btn = await page.query_selector(".nav-btn[data-page='devices']")
        if devices_btn:
            await devices_btn.click()
            await page.wait_for_timeout(1000)

            buttons = await page.query_selector_all("button")
            for btn in buttons:
                text = await btn.inner_text()
                if "连接" in text:
                    await btn.click()
                    await page.wait_for_timeout(5000)
                    break

        # 检查 SDK 状态
        sdk_state = await page.evaluate('''() => {
            var device = WebVideoCtrl.oDevice['192.168.5.72_80'];
            if (device) {
                return {
                    szIP: device.szIP,
                    szAuth: device.szAuth,
                    bSupportWebsocket: device.bSupportWebsocket,
                    iWebSocketPort: device.iWebSocketPort,
                    oStreamCapa: device.oStreamCapa
                };
            }
            return null;
        }''')

        print(f"\n=== SDK Device State ===")
        print(sdk_state)

        # 检查全局变量
        globals_state = await page.evaluate('''() => {
            return {
                g_bLoggedIn2: g_bLoggedIn2,
                g_szDeviceIdentify2: g_szDeviceIdentify2,
                g_iWebSocketPort: g_iWebSocketPort,
                g_iChannelID: g_iChannelID,
                connectedDevice: window.connectedDevice
            };
        }''')

        print(f"\n=== Global State ===")
        print(globals_state)

        await page.wait_for_timeout(5000)
        await browser.close()

if __name__ == "__main__":
    asyncio.run(main())

