# -*- coding: utf-8 -*-
"""检查 WebSocket 请求详情"""

import asyncio
from playwright.async_api import async_playwright

BASE_URL = "http://localhost:10280"

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        context = await browser.new_context()
        page = await context.new_page()

        # 收集 WebSocket 连接
        ws_connections = []

        page.on("websocket", lambda ws: ws_connections.append({
            "url": ws.url,
            "isClosed": ws.isClosed
        }))

        # 收集控制台日志
        logs = []
        page.on("console", lambda msg: logs.append(f"[{msg.type}] {msg.text}"))

        await page.goto(BASE_URL, wait_until="networkidle")
        await page.wait_for_timeout(2000)

        # 切换到设备管理
        await page.evaluate("window.switchPage('devices')")
        await page.wait_for_timeout(2000)

        # 点击连接
        await page.evaluate("""
            () => {
                const btns = document.querySelectorAll('button');
                for (const btn of btns) {
                    if (btn.textContent.includes('连接') && !btn.textContent.includes('断开')) {
                        btn.click();
                        return 'clicked';
                    }
                }
            }
        """)
        await page.wait_for_timeout(12000)

        # 打印 WebSocket 连接
        print("\n[WebSocket Connections]")
        for i, ws in enumerate(ws_connections):
            print(f"{i+1}. {ws['url']}")
            print(f"   Closed: {ws['isClosed']}")

        # 打印相关日志
        print("\n[Console Logs - WASM/Login/Play]")
        for log in logs:
            if any(x in log.lower() for x in ['wasm', 'login', 'play', 'websocket', 'error', 'fail']):
                print(f"  {log}")

        await browser.close()

if __name__ == "__main__":
    asyncio.run(main())

