# -*- coding: utf-8 -*-
"""修复右上角状态显示设备连接状态"""

file_path = r"C:\Users\admin\.openclaw\agents\dev-factory\astrohub\src\web\index.html"

with open(file_path, 'r', encoding='utf-8') as f:
    content = f.read()

# 修改 updateDeviceStatus 函数，同时更新右上角状态
old_update = """window.updateDeviceStatus = function() {
        var dot = document.getElementById('deviceDot');
        var status = document.getElementById('deviceStatus');
        if (!dot || !status) return;
        var connected = window.connectedDevice;
        if (connected) {
            dot.className = 'status-dot green';
            status.textContent = '已连接: ' + connected.ip;
        } else {
            dot.className = 'status-dot red';
            status.textContent = '已断开';
        }
    };"""

new_update = """window.updateDeviceStatus = function() {
        var dot = document.getElementById('deviceDot');
        var status = document.getElementById('deviceStatus');
        var wsDot = document.getElementById('wsDot');
        var wsStatus = document.getElementById('wsStatus');

        var connected = window.connectedDevice;

        // 更新左侧设备状态
        if (dot && status) {
            if (connected) {
                dot.className = 'status-dot green';
                status.textContent = '已连接: ' + connected.ip;
            } else {
                dot.className = 'status-dot red';
                status.textContent = '已断开';
            }
        }

        // 更新右上角状态（同步显示设备状态）
        if (wsDot && wsStatus) {
            if (connected) {
                wsDot.className = 'status-dot green';
                wsStatus.textContent = '已连接: ' + connected.ip;
            } else {
                wsDot.className = 'status-dot red';
                wsStatus.textContent = '已断开';
            }
        }
    };"""

content = content.replace(old_update, new_update)

# 更新版本号
content = content.replace('v5.38', 'v5.39')

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(content)

print("[OK] Updated status display - v5.39")

