# -*- coding: utf-8 -*-
"""验证右上角状态"""

import asyncio
from playwright.async_api import async_playwright

BASE_URL = "http://localhost:10280"

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        context = await browser.new_context()
        page = await context.new_page()

        await page.goto(BASE_URL, wait_until="networkidle")
        await page.wait_for_timeout(2000)

        version = await page.evaluate("document.querySelector('.version')?.textContent")
        print(f"Version: {version}")

        # 初始状态
        ws_status = await page.evaluate("""
            ({
                dot: document.getElementById('wsDot')?.className,
                text: document.getElementById('wsStatus')?.textContent
            })
        """)
        print(f"[Initial] Right-top: {ws_status['dot']} | {ws_status['text']}")

        # 连接设备
        await page.evaluate("window.switchPage('devices')")
        await page.wait_for_timeout(2000)
        await page.evaluate("""
            () => {
                const btns = document.querySelectorAll('button');
                for (const btn of btns) {
                    if (btn.textContent.includes('连接') && !btn.textContent.includes('断开')) {
                        btn.click();
                        return 'clicked';
                    }
                }
            }
        """)
        await page.wait_for_timeout(8000)

        # 检查连接后状态
        ws_status2 = await page.evaluate("""
            ({
                dot: document.getElementById('wsDot')?.className,
                text: document.getElementById('wsStatus')?.textContent,
                device: document.getElementById('deviceDot')?.className,
                deviceText: document.getElementById('deviceStatus')?.textContent
            })
        """)
        print(f"[Connected] Right-top: {ws_status2['dot']} | {ws_status2['text']}")
        print(f"[Connected] Left: {ws_status2['device']} | {ws_status2['deviceText']}")

        # 断开
        await page.evaluate("window.switchPage('devices')")
        await page.wait_for_timeout(2000)
        await page.evaluate("""
            () => {
                const btns = document.querySelectorAll('button');
                for (const btn of btns) {
                    if (btn.textContent.includes('断开')) {
                        btn.click();
                        return 'clicked';
                    }
                }
            }
        """)
        await page.wait_for_timeout(3000)

        # 检查断开后状态
        ws_status3 = await page.evaluate("""
            ({
                dot: document.getElementById('wsDot')?.className,
                text: document.getElementById('wsStatus')?.textContent,
                device: document.getElementById('deviceDot')?.className,
                deviceText: document.getElementById('deviceStatus')?.textContent
            })
        """)
        print(f"[Disconnected] Right-top: {ws_status3['dot']} | {ws_status3['text']}")
        print(f"[Disconnected] Left: {ws_status3['device']} | {ws_status3['deviceText']}")

        await browser.close()

if __name__ == "__main__":
    asyncio.run(main())

