# -*- coding: utf-8 -*-
"""追踪连接按钮的代码路径"""

import asyncio
from playwright.async_api import async_playwright

BASE_URL = "http://localhost:10280"

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        context = await browser.new_context()
        page = await context.new_page()

        logs = []
        page.on("console", lambda msg: logs.append(msg.text))

        await page.goto(BASE_URL, wait_until="networkidle")
        await page.wait_for_timeout(2000)

        # 切换到设备管理
        await page.evaluate("window.switchPage('devices')")
        await page.wait_for_timeout(2000)

        # 点击连接
        await page.evaluate("""
            () => {
                const btns = document.querySelectorAll('button');
                for (const btn of btns) {
                    if (btn.textContent.includes('连接') && !btn.textContent.includes('断开')) {
                        console.log('[TEST] Clicking button with onclick:', btn.getAttribute('onclick'));
                        btn.click();
                        return 'clicked';
                    }
                }
            }
        """)
        await page.wait_for_timeout(10000)

        # 检查 connectedDevice
        connected = await page.evaluate("window.connectedDevice")
        print(f"connectedDevice: {connected}")

        # 打印相关日志
        print("\n[Console logs]")
        for log in logs:
            if 'connect' in log.lower() or 'login' in log.lower() or 'update' in log.lower():
                print(f"  {log}")

        await browser.close()

if __name__ == "__main__":
    asyncio.run(main())

