# -*- coding: utf-8 -*-
"""在 v5.15 基础上添加设备状态功能"""

file_path = r"C:\Users\admin\.openclaw\agents\dev-factory\astrohub\src\web\index.html"

with open(file_path, 'r', encoding='utf-8') as f:
    content = f.read()

# 1. 在 </body> 前添加全局函数
global_script = """
    <!-- Global Functions (v5.20) -->
    <script>
    // 设备状态指示器更新函数
    window.updateDeviceStatus = function() {
        var dot = document.getElementById('deviceDot');
        var status = document.getElementById('deviceStatus');
        var wsDot = document.getElementById('wsDot');
        var wsStatus = document.getElementById('wsStatus');

        var connected = window.connectedDevice;

        // 更新左侧设备状态
        if (dot && status) {
            if (connected) {
                dot.className = 'status-dot green';
                status.textContent = '已连接: ' + connected.ip;
            } else {
                dot.className = 'status-dot red';
                status.textContent = '已断开';
            }
        }

        // 更新右上角状态
        if (wsDot && wsStatus) {
            if (connected) {
                wsDot.className = 'status-dot green';
                wsStatus.textContent = '已连接: ' + connected.ip;
            } else {
                wsDot.className = 'status-dot red';
                wsStatus.textContent = '已断开';
            }
        }

        console.log('[UI] Status updated:', connected ? connected.ip : 'none');
    };

    // 页面切换函数
    window.switchPage = function(page) {
        document.querySelectorAll('.nav-btn').forEach(function(b) { b.classList.remove('active'); });
        document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
        document.querySelector('[data-page="' + page + '"]').classList.add('active');
        document.getElementById('page-' + page).classList.add('active');
    };

    console.log('[GLOBAL v5.20] Functions ready');
    </script>
</body>"""

content = content.replace('</body>', global_script)

# 2. 在连接成功后调用 updateDeviceStatus
# 找到 connectDevice 中设置 window.connectedDevice 的位置
content = content.replace(
    "if (window.clickLogin2) { window.clickLogin2(); }",
    """if (window.clickLogin2) { window.clickLogin2(); }
                              if (window.updateDeviceStatus) window.updateDeviceStatus();"""
)

# 3. 在断开时清除状态
content = content.replace(
    "window.connectedDevice = null;",
    """window.connectedDevice = null;
                  if (window.updateDeviceStatus) window.updateDeviceStatus();"""
)

# 4. 更新版本号
content = content.replace('v5.15', 'v5.20')

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(content)

print("[OK] Added device status functions - v5.20")

