# 移除 ws.onopen 中的状态更新
content = content.replace(
    """ws.onopen = function() {
                      document.getElementById('wsDot').className = 'status-dot green';
                      document.getElementById('wsStatus').textContent = '已连接';
                      addLog('info', 'WebSocket 已连接');
                  };""",
