# -*- coding: utf-8 -*-
"""检查 wsDot 元素"""

import asyncio
from playwright.async_api import async_playwright

BASE_URL = "http://localhost:10280"

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        context = await browser.new_context()
        await context.clear_cookies()
        page = await context.new_page()

        await page.goto(BASE_URL + '?_t=' + str(int(asyncio.get_event_loop().time())))
        await page.wait_for_timeout(3000)

        # 检查元素
        result = await page.evaluate("""
            () => {
                var wsDot = document.getElementById('wsDot');
                var wsStatus = document.getElementById('wsStatus');
                return {
                    wsDot_exists: !!wsDot,
                    wsDot_class: wsDot ? wsDot.className : null,
                    wsStatus_exists: !!wsStatus,
                    wsStatus_text: wsStatus ? wsStatus.textContent : null,
                    wsDot_outerHTML: wsDot ? wsDot.outerHTML : null
                };
            }
        """)
